from typing import Dict, List, Optional, Any


class KongAdminAPI:
    def __init__(self, admin_url: str = "http://localhost:8001"):
        self.admin_url = admin_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({
            'Content-Type': 'application/json'
        })

    def _make_request(self, method: str, endpoint: str, data: Optional[Dict] = None) -> Dict:
        url = f"{self.admin_url}{endpoint}"
        try:
            if method == 'GET':
                response = self.session.get(url)
            elif method == 'POST':
                response = self.session.post(url, json=data)
            elif method == 'PUT':
                response = self.session.put(url, json=data)
            elif method == 'PATCH':
                response = self.session.patch(url, json=data)
            elif method == 'DELETE':
                response = self.session.delete(url)
            else:
                raise ValueError(f"Unsupported HTTP method: {method}")
            
            response.raise_for_status()
            return response.json() if response.text else {}
        except requests.exceptions.RequestException as e:
            print(f"Error making {method} request to {url}: {e}")
            if hasattr(e.response, 'text'):
                print(f"Response: {e.response.text}")
            raise

    def create_service(self, name: str, url: str, **kwargs) -> Dict:
        data = {
            'name': name,
            'url': url,
            **kwargs
        }
        print(f"Creating service: {name}")
        return self._make_request('POST', '/services', data)

    def get_service(self, name_or_id: str) -> Optional[Dict]:
        try:
            return self._make_request('GET', f'/services/{name_or_id}')
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return None
            raise

    def update_service(self, name_or_id: str, **kwargs) -> Dict:
        print(f"Updating service: {name_or_id}")
        return self._make_request('PATCH', f'/services/{name_or_id}', kwargs)

    def delete_service(self, name_or_id: str) -> Dict:
        print(f"Deleting service: {name_or_id}")
        return self._make_request('DELETE', f'/services/{name_or_id}')

    def list_services(self) -> List[Dict]:
        response = self._make_request('GET', '/services')
        return response.get('data', [])

    def create_route(self, service_name_or_id: str, paths: List[str], 
                     methods: Optional[List[str]] = None, 
                     hosts: Optional[List[str]] = None,
                     name: Optional[str] = None,
                     **kwargs) -> Dict:
        data = {
            'paths': paths,
            **kwargs
        }
        if methods:
            data['methods'] = methods
        if hosts:
            data['hosts'] = hosts
        if name:
            data['name'] = name
        
        print(f"Creating route for service: {service_name_or_id}")
        return self._make_request('POST', f'/services/{service_name_or_id}/routes', data)

    def get_route(self, route_id: str) -> Optional[Dict]:
        try:
            return self._make_request('GET', f'/routes/{route_id}')
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return None
            raise

    def update_route(self, route_id: str, **kwargs) -> Dict:
        print(f"Updating route: {route_id}")
        return self._make_request('PATCH', f'/routes/{route_id}', kwargs)

    def delete_route(self, route_id: str) -> Dict:
        print(f"Deleting route: {route_id}")
        return self._make_request('DELETE', f'/routes/{route_id}')

    def list_routes(self, service_name_or_id: Optional[str] = None) -> List[Dict]:
        if service_name_or_id:
            response = self._make_request('GET', f'/services/{service_name_or_id}/routes')
        else:
            response = self._make_request('GET', '/routes')
        return response.get('data', [])

    def create_upstream(self, name: str, **kwargs) -> Dict:
        data = {
            'name': name,
            **kwargs
        }
        print(f"Creating upstream: {name}")
        return self._make_request('POST', '/upstreams', data)

    def get_upstream(self, name_or_id: str) -> Optional[Dict]:
        try:
            return self._make_request('GET', f'/upstreams/{name_or_id}')
        except requests.exceptions.HTTPError as e:
            if e.response.status_code == 404:
                return None
            raise

    def update_upstream(self, name_or_id: str, **kwargs) -> Dict:
        print(f"Updating upstream: {name_or_id}")
        return self._make_request('PATCH', f'/upstreams/{name_or_id}', kwargs)

    def delete_upstream(self, name_or_id: str) -> Dict:
        print(f"Deleting upstream: {name_or_id}")
        return self._make_request('DELETE', f'/upstreams/{name_or_id}')

    def list_upstreams(self) -> List[Dict]:
        response = self._make_request('GET', '/upstreams')
