def configure_kong_example():
    kong = KongAdminAPI(admin_url="http://localhost:8001")
    
    try:
        status = kong.health_check()
        print(f"Kong status: {json.dumps(status, indent=2)}")
    except Exception as e:
        print(f"Failed to connect to Kong Admin API: {e}")
        return

    service1 = kong.create_service(
        name="example-service",
        url="http://httpbin.org",
        protocol="http",
        connect_timeout=60000,
        write_timeout=60000,
        read_timeout=60000
    )
    print(f"Created service: {service1['id']}")

    route1 = kong.create_route(
        service_name_or_id=service1['id'],
        name="example-route",
        paths=["/api/v1"],
        methods=["GET", "POST"],
        strip_path=True
    )
    print(f"Created route: {route1['id']}")

    upstream1 = kong.create_upstream(
        name="example-upstream",
        algorithm="round-robin",
        slots=1000
    )
    print(f"Created upstream: {upstream1['id']}")

    target1 = kong.create_target(
        upstream_name_or_id=upstream1['id'],
        target="backend1.example.com:8080",
        weight=100
    )
    print(f"Created target: {target1['id']}")

    target2 = kong.create_target(
        upstream_name_or_id=upstream1['id'],
        target="backend2.example.com:8080",
        weight=100
    )
    print(f"Created target: {target2['id']}")

    service2 = kong.create_service(
        name="load-balanced-service",
        host=upstream1['name'],
        protocol="http",
        path="/api"
    )
    print(f"Created load-balanced service: {service2['id']}")

    route2 = kong.create_route(
        service_name_or_id=service2['id'],
        name="load-balanced-route",
        paths=["/balanced"],
        methods=["GET", "POST", "PUT", "DELETE"]
    )
    print(f"Created load-balanced route: {route2['id']}")

    rate_limit_plugin = kong.add_plugin(
        plugin_name="rate-limiting",
        service_id=service1['id'],
        config={
            "minute": 100,
            "policy": "local"
        }
    )
    print(f"Added rate-limiting plugin: {rate_limit_plugin['id']}")

    cors_plugin = kong.add_plugin(
        plugin_name="cors",
        route_id=route1['id'],
        config={
            "origins": ["*"],
            "methods": ["GET", "POST"],
            "headers": ["Accept", "Content-Type"],
            "exposed_headers": ["X-Auth-Token"],
            "credentials": True,
            "max_age": 3600
        }
    )
    print(f"Added CORS plugin: {cors_plugin['id']}")

    print("\n=== Configuration Summary ===")
    print(f"\nServices:")
    for service in kong.list_services():
        print(f"  - {service['name']} ({service['id']})")

    print(f"\nRoutes:")
    for route in kong.list_routes():
        print(f"  - {route.get('name', 'unnamed')} ({route['id']})")

    print(f"\nUpstreams:")
    for upstream in kong.list_upstreams():
        print(f"  - {upstream['name']} ({upstream['id']})")
        targets = kong.list_targets(upstream['id'])
        for target in targets:
            print(f"    * {target['target']} (weight: {target['weight']})")

    print(f"\nPlugins:")
    for plugin in kong.list_plugins():
        print(f"  - {plugin['name']} ({plugin['id']})")


def configure_microservices_architecture():
    kong = KongAdminAPI(admin_url="http://localhost:8001")
    
    microservices = [
        {
            "name": "user-service",
            "upstream": "user-service-upstream",
            "targets": [
                {"host": "user-service-1:8080", "weight": 100},
                {"host": "user-service-2:8080", "weight": 100}
            ],
            "route_path": "/users",
            "methods": ["GET", "POST", "PUT", "DELETE"]
        },
        {
            "name": "order-service",
            "upstream": "order-service-upstream",
            "targets": [
                {"host": "order-service-1:8080", "weight": 150},
                {"host": "order-service-2:8080", "weight": 100},
                {"host": "order-service-3:8080", "weight": 50}
            ],
            "route_path": "/orders",
            "methods": ["GET", "POST", "PUT", "DELETE"]
        },
        {
            "name": "product-service",
            "upstream": "product-service-upstream",
            "targets": [
                {"host": "product-service-1:8080", "weight": 100}
            ],
            "route_path": "/products",
            "methods": ["GET", "POST", "PUT", "DELETE"]
        }
    ]
    
    for ms in microservices:
        upstream = kong.create_upstream(
            name=ms["upstream"],
            algorithm="round-robin"
        )
        print(f"Created upstream: {upstream['name']}")
        
        for target_config in ms["targets"]:
            target = kong.create_target(
                upstream_name_or_id=upstream['id'],
                target=target_config["host"],
                weight=target_config["weight"]
            )
            print(f"  Added target: {target['target']}")
        
        service = kong.create_service(
            name=ms["name"],
            host=upstream['name'],
            protocol="http",
            port=80,
            connect_timeout=5000,
            write_timeout=5000,
            read_timeout=5000
        )
        print(f"Created service: {service['name']}")
        
        route = kong.create_route(
            service_name_or_id=service['id'],
            name=f"{ms['name']}-route",
            paths=[ms["route_path"]],
            methods=ms["methods"],
            strip_path=False
        )
        print(f"Created route: {route['name']}")
        
        kong.add_plugin(
            plugin_name="rate-limiting",
            service_id=service['id'],
            config={
                "minute": 1000,
                "hour": 10000,
                "policy": "local"
            }
        )
        print(f"  Added rate-limiting plugin")
        
        kong.add_plugin(
            plugin_name="request-transformer",
            service_id=service['id'],
            config={
                "add": {
                    "headers": [f"X-Service-Name:{ms['name']}"]
                }
            }
        )
        print(f"  Added request-transformer plugin")
    
    print("\n=== Microservices Architecture Configured ===")


